pages.css:
.page-01 {
  width: 1242px;
  height: 1660px;
  background-color: #F4F4F2;
  padding: 100px 96px;
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
}

.page-header {
  display: flex;
  align-items: center;
  gap: 20px;
}

.header-icon {
  font-size: 46px;
}

.header-label {
  font-size: 38px;
  font-weight: 600;
  color: #888888;
  letter-spacing: 0;
}

.title-section {
  margin-top: 280px;
  flex: 1;
}

.page-title {
  display: flex;
  flex-direction: column;
  gap: 32px;
}

.title-line {
  font-size: 128px;
  font-weight: 900;
  color: #111111;
  line-height: 1.1;
  letter-spacing: 0;
}

.proof-list {
  display: flex;
  flex-direction: column;
  gap: 64px;
  margin-bottom: 60px;
}

.proof-item {
  display: flex;
  gap: 48px;
  border-top: 3px solid #D1D1D1;
  padding-top: 48px;
}

.proof-tag {
  font-size: 38px;
  font-weight: 700;
  color: #D93829;
  width: 110px;
  flex-shrink: 0;
  line-height: 1.6;
}

.proof-text {
  font-size: 42px;
  line-height: 1.6;
  color: #222222;
  font-weight: 400;
}

.page {
  width: 1242px;
  height: 1660px;
  background-color: #F8F9FA;
  color: #1A1A1A;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  box-sizing: border-box;
  padding: 100px 96px;
  position: relative;
  display: flex;
  flex-direction: column;
}

.page-header {
  display: flex;
  align-items: center;
  gap: 16px;
  margin-bottom: 48px;
}

.header-icon {
  font-size: 40px;
}

.header-label {
  font-size: 36px;
  color: #666666;
  font-weight: 600;
}

.title-section {
  margin-bottom: 48px;
}

.page-title {
  font-size: 116px;
  font-weight: 800;
  line-height: 1.25;
  color: #111111;
}

.metric-section {
  background-color: #FFFFFF;
  border-radius: 16px;
  padding: 40px 40px;
  margin-bottom: 48px;
  border-left: 12px solid #D90429;
  box-shadow: 0 12px 32px rgba(0,0,0,0.05);
}

.metric-value {
  font-size: 104px;
  font-weight: 900;
  color: #D90429;
  margin-bottom: 16px;
  line-height: 1;
}

.metric-label {
  font-size: 38px;
  color: #444444;
  font-weight: 500;
}

.proof-list {
  display: flex;
  flex-direction: column;
  gap: 32px;
  flex: 1;
}

.proof-item {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.proof-tag {
  display: inline-block;
  font-size: 34px;
  font-weight: 700;
  color: #D90429;
  background-color: rgba(217, 4, 41, 0.08);
  padding: 8px 20px;
  border-radius: 8px;
  align-self: flex-start;
}

.proof-text {
  font-size: 42px;
  color: #2B2B2B;
  line-height: 1.6;
  font-weight: 400;
}

.page-footer {
  position: absolute;
  bottom: 80px;
  left: 96px;
  right: 96px;
  border-top: 2px solid #E5E5E5;
  padding-top: 24px;
}

.footnote {
  font-size: 32px;
  color: #888888;
  line-height: 1.5;
}

.page-03 {
  width: 1242px;
  height: 1660px;
  background-color: #F8F9FA;
  box-sizing: border-box;
  padding: 104px 96px;
  display: flex;
  flex-direction: column;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  color: #1A1A1A;
}

.header {
  display: flex;
  align-items: center;
  font-size: 40px;
  color: #666666;
  font-weight: 500;
  margin-bottom: 56px;
}

.header-icon {
  margin-right: 16px;
  font-size: 44px;
}

.page-title {
  font-size: 124px;
  font-weight: 900;
  line-height: 1.15;
  margin-bottom: 64px;
  letter-spacing: 0;
  color: #1A1A1A;
}

.page-title p {
  margin: 0;
}

.highlight-box {
  background-color: #FFFFFF;
  border-radius: 16px;
  padding: 40px 48px;
  margin-bottom: 64px;
  border-left: 12px solid #1A56DB;
  box-shadow: 0 16px 40px rgba(26, 86, 219, 0.06);
}

.highlight-sub {
  font-size: 40px;
  color: #666666;
  margin-bottom: 12px;
  font-weight: 500;
}

.highlight-main {
  font-size: 104px;
  font-weight: 900;
  color: #1A56DB;
  line-height: 1.1;
  letter-spacing: 0;
}

.proof-list {
  display: flex;
  flex-direction: column;
  gap: 40px;
}

.proof-item {
  display: flex;
  align-items: flex-start;
  gap: 24px;
}

.proof-tag {
  flex-shrink: 0;
  background-color: #EBF1FF;
  color: #1A56DB;
  font-size: 38px;
  padding: 8px 16px;
  border-radius: 8px;
  font-weight: 600;
  line-height: 1;
  margin-top: 6px;
}

.proof-text {
  font-size: 42px;
  line-height: 1.55;
  color: #333333;
  font-weight: 400;
}

.footnote {
  margin-top: auto;
  font-size: 36px;
  color: #999999;
  border-top: 2px solid #E5E5E5;
  padding-top: 32px;
  line-height: 1.4;
}

.page {
  width: 1242px;
  height: 1660px;
  background-color: #F8F9FA;
  box-sizing: border-box;
  padding: 90px 100px;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  position: relative;
}

.page-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 36px;
  color: #888888;
  font-weight: 600;
  margin-bottom: 50px;
  line-height: 1;
  letter-spacing: 0;
}

.page-title {
  margin-bottom: 60px;
}

.page-title p {
  font-size: 106px;
  font-weight: 900;
  line-height: 1.2;
  color: #111111;
  margin: 0;
  letter-spacing: 0;
}

.page-title p.highlight {
  color: #D90429;
}

.proof-list {
  display: flex;
  flex-direction: column;
  gap: 24px;
}

.proof-item {
  background-color: #FFFFFF;
  border-radius: 16px;
  padding: 32px 40px;
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.03);
  border: 1px solid #EFEFEF;
  border-left: 8px solid #D90429;
}

.proof-tag {
  display: inline-block;
  font-size: 34px;
  font-weight: 800;
  color: #D90429;
  background-color: #FFF0F1;
  padding: 8px 16px;
  border-radius: 6px;
  margin-bottom: 20px;
  line-height: 1;
  letter-spacing: 0;
}

.proof-text {
  font-size: 38px;
  line-height: 1.55;
  color: #333333;
  font-weight: 400;
  margin: 0;
  letter-spacing: 0;
}

.page-05 {
  width: 1242px;
  height: 1660px;
  background-color: #F8F9FA;
  color: #1A1A1A;
  box-sizing: border-box;
  padding: 100px 90px;
  position: relative;
  display: flex;
  flex-direction: column;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  letter-spacing: 0;
}

.page-header {
  display: flex;
  align-items: center;
  gap: 16px;
  margin-bottom: 60px;
}

.header-icon {
  font-size: 40px;
}

.header-label {
  font-size: 38px;
  color: #666666;
  font-weight: 500;
}

.title-section {
  margin-bottom: 80px;
}

.page-title {
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.title-line {
  font-size: 120px;
  font-weight: 900;
  line-height: 1.1;
  color: #111111;
}

.content-section {
  flex: 1;
  display: flex;
  flex-direction: column;
}

.sub-list {
  display: flex;
  flex-direction: column;
  gap: 40px;
}

.sub-item {
  display: flex;
  flex-direction: column;
  gap: 20px;
  padding-bottom: 40px;
  border-bottom: 2px solid #E5E5E5;
}

.sub-item:last-child {
  border-bottom: none;
  padding-bottom: 0;
}

.sub-tag {
  display: inline-flex;
  align-items: center;
  font-size: 38px;
  font-weight: 700;
  color: #E02020;
  background-color: rgba(224, 32, 32, 0.08);
  padding: 10px 24px;
  border-radius: 8px;
  width: fit-content;
}

.sub-text {
  font-size: 42px;
  line-height: 1.6;
  color: #333333;
  font-weight: 400;
}
